/**
 * SlaIntegrationSplitPropertyPanel
 * Author: generated by Amazon Q
 * Created: 2025-01-01
 * Purpose: Full visual editor for SlaIntegrationSplitSection fields
 */

'use client';

import React, { useState } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';

interface Props {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{label}</label>
      {children}
    </div>
  );
}

const inputCls = 'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';
const textareaCls = inputCls + ' resize-none';

function Collapsible({ title, badge, children, defaultOpen = false }: {
  title: string; badge?: string; children: React.ReactNode; defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden">
      <button type="button" onClick={() => setOpen(o => !o)}
        className="w-full flex items-center justify-between px-3 py-2.5 bg-gray-50 dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors text-left">
        <span className="text-sm font-medium text-gray-800 dark:text-white flex items-center gap-2">
          {title}
          {badge && <span className="text-xs bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded-full">{badge}</span>}
        </span>
        <span className={`text-gray-400 text-xs transition-transform ${open ? 'rotate-90' : ''}`}>▶</span>
      </button>
      {open && <div className="p-3 space-y-3 bg-white dark:bg-gray-800">{children}</div>}
    </div>
  );
}

function CardEditor({ title, cardKey, data, onUpdate }: {
  title: string;
  cardKey: 'leftCard' | 'rightCard';
  data: any;
  onUpdate: (patch: Record<string, any>) => void;
}) {
  const card = data[cardKey] ?? {};
  const features = card.features ?? [];

  const updateCard = (field: string, val: any) => {
    onUpdate({ [cardKey]: { ...card, [field]: val } });
  };

  const updateFeature = (idx: number, val: string) => {
    const next = features.map((f: string, i: number) => i === idx ? val : f);
    updateCard('features', next);
  };

  return (
    <Collapsible title={title} defaultOpen>
      <Field label="Tag (eyebrow)">
        <input className={inputCls} value={card.tag ?? ''} onChange={e => updateCard('tag', e.target.value)} />
      </Field>
      <Field label="Title (use \\n for line breaks)">
        <textarea className={textareaCls} rows={2} value={card.title ?? ''} onChange={e => updateCard('title', e.target.value)} />
      </Field>
      <Field label="Body">
        <textarea className={textareaCls} rows={4} value={card.body ?? ''} onChange={e => updateCard('body', e.target.value)} />
      </Field>
      <Field label="Features (one per line)">
        <textarea
          className={textareaCls}
          rows={6}
          value={features.join('\n')}
          onChange={e => updateCard('features', e.target.value.split('\n').map((f: string) => f.trim()).filter(Boolean))}
        />
      </Field>
    </Collapsible>
  );
}

export function SlaIntegrationSplitPropertyPanel({ section, onUpdate }: Props) {
  const data = section.data as any;
  const update = (patch: Record<string, any>) => onUpdate({ data: { ...data, ...patch } });

  return (
    <div className="space-y-4">

      <CardEditor title="Left Card — SLA Management" cardKey="leftCard" data={data} onUpdate={update} />
      <CardEditor title="Right Card — Integration Hub" cardKey="rightCard" data={data} onUpdate={update} />

      <Collapsible title="Accent Colors">
        <div className="grid grid-cols-2 gap-2">
          {(['accentColor', 'accentColor2'] as const).map((key, i) => (
            <Field key={key} label={['Primary', 'Secondary'][i]}>
              <div className="flex gap-1 items-center">
                <input type="color" value={data[key] ?? '#4F7FFF'} onChange={e => update({ [key]: e.target.value })}
                  className="w-9 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700" />
                <input className={inputCls} value={data[key] ?? ''} onChange={e => update({ [key]: e.target.value })} />
              </div>
            </Field>
          ))}
        </div>
      </Collapsible>

    </div>
  );
}
